import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DDNAyvCW.js";const p=JSON.parse('{"title":"Terminal Operations","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/operations/index.md","filePath":"docs/terminal/operations/index.md"}'),i={name:"docs/terminal/operations/index.md"};function n(d,t,l,s,c,h){return o(),a("div",null,t[0]||(t[0]=[r('<h1 id="terminal-operations" tabindex="-1">Terminal Operations <a class="header-anchor" href="#terminal-operations" aria-label="Permalink to &quot;Terminal Operations&quot;">​</a></h1><p>The terminal is the core feature of Chaterm -- a full SSH terminal experience with splits, search, and keyboard-driven workflows.</p><h2 id="terminal-connection" tabindex="-1">Terminal Connection <a class="header-anchor" href="#terminal-connection" aria-label="Permalink to &quot;Terminal Connection&quot;">​</a></h2><p>After you connect to a host, a terminal window opens automatically. The terminal supports:</p><ul><li><strong>Full-featured SSH terminal</strong> with all standard commands and operations.</li><li><strong>Multi-tab management</strong> to run several sessions at once and switch between them.</li><li><strong>Tab renaming</strong> for quick identification (right-click a tab to rename).</li><li><strong>Tab cloning</strong> to duplicate a session on the same host.</li></ul><h2 id="terminal-splitting" tabindex="-1">Terminal Splitting <a class="header-anchor" href="#terminal-splitting" aria-label="Permalink to &quot;Terminal Splitting&quot;">​</a></h2><p>Split the terminal to view multiple sessions side by side or stacked. Each split pane is an independent terminal session that can connect to a different host or run different commands.</p><h3 id="how-to-split" tabindex="-1">How to Split <a class="header-anchor" href="#how-to-split" aria-label="Permalink to &quot;How to Split&quot;">​</a></h3><ol><li>Open the tab menu bar or right-click inside the terminal.</li><li>Choose <strong>Split Right</strong> or <strong>Split Down</strong>.</li><li>A new terminal pane appears in the chosen direction.</li><li>Each pane operates independently -- type commands, resize, or close them individually.</li></ol><h3 id="split-shortcuts" tabindex="-1">Split Shortcuts <a class="header-anchor" href="#split-shortcuts" aria-label="Permalink to &quot;Split Shortcuts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>Split Right</td><td>Via tab menu</td><td>Via tab menu</td></tr><tr><td>Split Down</td><td>Via tab menu</td><td>Via tab menu</td></tr><tr><td>Clone Session</td><td>Via tab menu</td><td>Via tab menu</td></tr></tbody></table><blockquote><p><strong>Tip:</strong> Use a side-by-side split to watch logs on the left while running commands on the right. Use a stacked split to monitor system metrics on top while operating below.</p></blockquote><h2 id="terminal-search" tabindex="-1">Terminal Search <a class="header-anchor" href="#terminal-search" aria-label="Permalink to &quot;Terminal Search&quot;">​</a></h2><p>Search through terminal output to find commands, error messages, or any text.</p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li>Press <code>Cmd + F</code> (macOS) or <code>Ctrl + F</code> (Windows/Linux) to open the search bar.</li><li>Type your search query.</li><li>Matching text is highlighted in the terminal output.</li><li>Click <strong>Previous</strong> / <strong>Next</strong> (or use arrow buttons) to jump between matches.</li><li>Press <code>Esc</code> to close the search bar.</li></ol><h3 id="search-shortcuts" tabindex="-1">Search Shortcuts <a class="header-anchor" href="#search-shortcuts" aria-label="Permalink to &quot;Search Shortcuts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>Open Search</td><td><code>Cmd + F</code></td><td><code>Ctrl + F</code></td></tr><tr><td>Close Search</td><td><code>Esc</code></td><td><code>Esc</code></td></tr></tbody></table><h2 id="right-click-menu-operations" tabindex="-1">Right-Click Menu Operations <a class="header-anchor" href="#right-click-menu-operations" aria-label="Permalink to &quot;Right-Click Menu Operations&quot;">​</a></h2><p>Right-click anywhere in the terminal to open the context menu.</p><h3 id="clipboard" tabindex="-1">Clipboard <a class="header-anchor" href="#clipboard" aria-label="Permalink to &quot;Clipboard&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>macOS</th><th>Windows/Linux</th><th>Description</th></tr></thead><tbody><tr><td><strong>Copy</strong></td><td><code>Cmd + C</code></td><td><code>Ctrl + C</code></td><td>Copy the selected text</td></tr><tr><td><strong>Paste</strong></td><td><code>Cmd + V</code></td><td><code>Ctrl + V</code></td><td>Paste clipboard content</td></tr></tbody></table><h3 id="display" tabindex="-1">Display <a class="header-anchor" href="#display" aria-label="Permalink to &quot;Display&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>macOS</th><th>Windows/Linux</th><th>Description</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td><code>Cmd + F</code></td><td><code>Ctrl + F</code></td><td>Open the search bar</td></tr><tr><td><strong>Clear</strong></td><td>Via right-click</td><td>Via right-click</td><td>Clear visible terminal output</td></tr><tr><td><strong>Font Size</strong></td><td>Via right-click</td><td>Via right-click</td><td>Scale the terminal font up or down</td></tr></tbody></table><h3 id="connection" tabindex="-1">Connection <a class="header-anchor" href="#connection" aria-label="Permalink to &quot;Connection&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td><strong>Disconnect</strong></td><td>Disconnect the current SSH connection</td></tr><tr><td><strong>New Terminal</strong></td><td>Open a new terminal session</td></tr><tr><td><strong>Close Terminal</strong></td><td>Close the current terminal session</td></tr></tbody></table><h3 id="splits" tabindex="-1">Splits <a class="header-anchor" href="#splits" aria-label="Permalink to &quot;Splits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td><strong>Split Right</strong></td><td>Create a horizontal split pane</td></tr><tr><td><strong>Split Down</strong></td><td>Create a vertical split pane</td></tr></tbody></table><h2 id="all-keyboard-shortcuts" tabindex="-1">All Keyboard Shortcuts <a class="header-anchor" href="#all-keyboard-shortcuts" aria-label="Permalink to &quot;All Keyboard Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>Copy</td><td><code>Cmd + C</code></td><td><code>Ctrl + C</code></td></tr><tr><td>Paste</td><td><code>Cmd + V</code></td><td><code>Ctrl + V</code></td></tr><tr><td>Search</td><td><code>Cmd + F</code></td><td><code>Ctrl + F</code></td></tr><tr><td>AI Command Dialog</td><td><code>Cmd + K</code></td><td><code>Ctrl + K</code></td></tr><tr><td>AI Sidebar</td><td><code>Cmd + L</code></td><td><code>Ctrl + L</code></td></tr></tbody></table><p>For the full shortcut list, see <a href="/docs/settings/shortcuts/">Shortcuts Settings</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/docs/terminal/manage/">Terminal Management</a> -- tabs, cloning, and closing sessions.</li><li><a href="/docs/settings/shortcuts/">Shortcuts Settings</a> -- view and customize all keyboard shortcuts.</li></ul>',33)]))}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
